// frontend/src/components/Toast.js
import React, { useEffect } from 'react';

export default function Toast({ message, type = 'success', onClose }) {
  useEffect(() => {
    const t = setTimeout(onClose, 3000);
    return () => clearTimeout(t);
  }, [onClose]);

  const colors = {
    success: { bg: '#0f6e56', border: '#1D9E75' },
    error:   { bg: '#c0392b', border: '#e74c3c' },
    info:    { bg: '#2980b9', border: '#3498db' },
  };
  const c = colors[type] || colors.success;

  return (
    <div style={{
      position: 'fixed', bottom: '28px', left: '50%',
      transform: 'translateX(-50%)',
      background: c.bg, color: '#fff',
      padding: '12px 24px', borderRadius: '40px',
      fontSize: '14px', fontWeight: '500',
      boxShadow: '0 4px 20px rgba(0,0,0,0.2)',
      zIndex: 9999, whiteSpace: 'nowrap',
      animation: 'fadeUp .3s ease',
    }}>
      {message}
      <style>{`@keyframes fadeUp { from { opacity:0; transform:translateX(-50%) translateY(12px); } to { opacity:1; transform:translateX(-50%) translateY(0); } }`}</style>
    </div>
  );
}
